import { writable } from 'svelte/store';

const DEFAULT_HIGHLIGHT = {
	primaryCell: null,
	cells: [],
	kind: null,
};

function normalizeCell(cell) {
	if (!cell) {
		return null;
	}

	return {
		row: cell.row,
		col: cell.col,
	};
}

function createHighlight() {
	const store = writable(DEFAULT_HIGHLIGHT);

	return {
		subscribe: store.subscribe,

		set({ primaryCell = null, cells = [], kind = null } = {}) {
			store.set({
				primaryCell: normalizeCell(primaryCell),
				cells: cells.map(normalizeCell).filter(Boolean),
				kind,
			});
		},

		focus(cell, kind = 'focus') {
			const normalizedCell = normalizeCell(cell);
			this.set({
				primaryCell: normalizedCell,
				cells: normalizedCell ? [normalizedCell] : [],
				kind,
			});
		},

		clear() {
			store.set(DEFAULT_HIGHLIGHT);
		},
	};
}

export const highlight = createHighlight();
